20	impl App {
21	    pub fn new() -> Result<Self> {
22	        // Load first profile found
23	        let profiles_dir = crate::pack::get_profiles_dir()?;
24	        let first_profile = std::fs::read_dir(profiles_dir)?
25	            .filter_map(|e| e.ok())
26	            .find(|e| e.path().is_dir());
27	
28	        let pack = if let Some(p) = first_profile {
29	            crate::pack::Pack::load_from_dir(&p.path()).ok()
30	        } else {
31	            None
32	        };
33	
34	        Ok(Self {
35	            pack,
36	            selected_category: 0,
37	            selected_macro: 0,
38	            mode: AppMode::Browser,
39	        })
40	    }
41	
42	    pub fn draw(&mut self, f: &mut Frame) {
43	        let chunks = Layout::default()
44	            .direction(Direction::Vertical)
45	            .constraints([Constraint::Length(3), Constraint::Min(0), Constraint::Length(3)])
46	            .split(f.area());
47	
48	        // Header
49	        let header = Paragraph::new(" VIBE-ATTACK // TACTICAL MACRO EDITOR ")
50	            .block(Block::default().borders(Borders::ALL).border_type(BorderType::Thick))
51	            .style(Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD))
52	            .alignment(Alignment::Center);
53	        f.render_widget(header, chunks[0]);
54	
55	        // Main content
56	        let main_chunks = Layout::default()
57	            .direction(Direction::Horizontal)
58	            .constraints([Constraint::Percentage(30), Constraint::Percentage(70)])
59	            .split(chunks[1]);
60	
61	        // Categories List
62	        let categories = Block::default()
63	            .title(" Categories ")
64	            .borders(Borders::ALL)
65	            .border_style(Style::default().fg(Color::Yellow));
66	        f.render_widget(categories, main_chunks[0]);
67	
68	        // Macros List
69	        let macros = Block::default()
70	            .title(" Macros ")
71	            .borders(Borders::ALL)
72	            .border_style(Style::default().fg(Color::Yellow));
73	        f.render_widget(macros, main_chunks[1]);
74	
75	        // Footer
76	        let footer = Paragraph::new(" [q] Quit | [Arrows] Navigate | [Enter] Edit | [t] Test ")
77	            .block(Block::default().borders(Borders::ALL))
78	            .style(Style::default().fg(Color::DarkGray));
79	        f.render_widget(footer, chunks[2]);
80	    }
81	
82	    pub fn handle_key(&mut self, code: KeyCode) {
83	        match self.mode {
84	            AppMode::Browser => {
85	                if let Some(pack) = &self.pack {
86	                    match code {
87	                        KeyCode::Up if self.selected_macro > 0 => {
88	                            self.selected_macro -= 1;
89	                        }
90	                        KeyCode::Down => {
91	                            let cat = &pack.categories[self.selected_category];
92	                            if self.selected_macro < cat.macros.len() - 1 {
93	                                self.selected_macro += 1;
94	                            }
95	                        }
96	                        KeyCode::Left if self.selected_category > 0 => {
97	                            self.selected_category -= 1;
98	                            self.selected_macro = 0;
99	                        }
100	                        KeyCode::Right if self.selected_category < pack.categories.len() - 1 => {
101	                            self.selected_category += 1;
102	                            self.selected_macro = 0;
103	                        }
104	                        KeyCode::Enter => {
105	                            self.mode = AppMode::Editor;
106	                        }
107	                        _ => {}
108	                    }
109	                }
110	            }
111	            AppMode::Editor => {
112	                if code == KeyCode::Esc {
113	                    self.mode = AppMode::Browser;
114	                }
115	            }
116	        }
117	    }
118	}
