29	                    Style::default().fg(Color::Cyan)
30	                ),
31	            ]),
32	            Line::from(vec![
33	                Span::raw("Condition: "),
34	                Span::styled(
35	                    self.macro_config.if_flag.as_deref().unwrap_or("<none>"),
36	                    Style::default().fg(Color::Cyan)
37	                ),
38	            ]),
39	            Line::from(""),
40	            Line::from(Span::styled("Key Sequence:", Style::default().add_modifier(Modifier::UNDERLINED))),
41	        ];
42	
43	        let mut items = text;
44	        for (i, key) in self.macro_config.keys.iter().enumerate() {
45	            items.push(Line::from(format!("  {}. {}", i + 1, key.key)));
46	        }
47	
48	        let paragraph = Paragraph::new(items).block(block);
49	        f.render_widget(paragraph, area);
50	    }
51	}
